import math
import pathlib

import pytest
import yaml

import graph
from uniform_cost_search import uniform_cost_search


FIXTURES_DIR = pathlib.Path(__file__).parent / 'fixtures' / 'ucs'


def _load_fixture(path):
    with open(path) as f:
        return yaml.safe_load(f)


def _build(fixture):
    G = graph.Graph(directed=fixture['directed'])
    vertices = {}
    for src, dst, weight in fixture['edges']:
        if src not in vertices:
            vertices[src] = G.insert_vertex(src)
        if dst not in vertices:
            vertices[dst] = G.insert_vertex(dst)
        # uniform_cost_search reads weights from edge.element(), so
        # the weight is stored on the edge directly (not in a side map
        # like create_graph + (G, w) does).
        G.insert_edge(vertices[src], vertices[dst], weight)
    start = G.get_vertex(fixture['start'])
    goal = G.get_vertex(fixture['goal'])
    return G, start, goal


FIXTURE_FILES = sorted(p.name for p in FIXTURES_DIR.glob('*.yml'))


@pytest.mark.parametrize('fixture_file', FIXTURE_FILES)
def test_uniform_cost_search_matches_fixture(fixture_file):
    fixture = _load_fixture(FIXTURES_DIR / fixture_file)
    G, start, goal = _build(fixture)

    path, length = uniform_cost_search(G, start, goal)

    if not fixture['expected_path']:
        assert path == []
        assert length == math.inf
    else:
        assert [v.element() for v in path] == fixture['expected_path']
        assert length == pytest.approx(fixture['expected_length'])


def _build_edges(edges, directed=True):
    G = graph.Graph(directed=directed)
    vertices = {}
    for src, dst, weight in edges:
        if src not in vertices:
            vertices[src] = G.insert_vertex(src)
        if dst not in vertices:
            vertices[dst] = G.insert_vertex(dst)
        G.insert_edge(vertices[src], vertices[dst], weight)
    return G, vertices


def test_start_equals_goal():
    G, vertices = _build_edges([('a', 'b', 1), ('b', 'c', 1)])
    path, length = uniform_cost_search(G, vertices['a'], vertices['a'])
    assert [v.element() for v in path] == ['a']
    assert length == 0


def test_prefers_cheaper_multi_hop_over_direct_edge():
    # direct a->c is 10; a->b->c is 1+1=2 — UCS must pick the cheaper
    # multi-hop route rather than the single expensive edge.
    G, vertices = _build_edges([
        ('a', 'b', 1),
        ('b', 'c', 1),
        ('a', 'c', 10),
    ])
    path, length = uniform_cost_search(G, vertices['a'], vertices['c'])
    assert [v.element() for v in path] == ['a', 'b', 'c']
    assert length == 2

